async function initProfilePage(){requireAuth()&&(initTabs(document.getElementById("profile-tabs")),await loadProfile(),await loadFavorites(),initSettingsForm())}async function loadProfile(){const e=document.getElementById("profile-card");try{const t=AuthState.getUser()||await Auth.me();t&&AuthState.save(AuthState.getToken(),t),e.innerHTML=`\n      <div style="display:flex;align-items:center;gap:20px;flex-wrap:wrap;">\n        <div style="width:72px;height:72px;border-radius:50%;background:linear-gradient(135deg,var(--teal),var(--teal-dark));display:flex;align-items:center;justify-content:center;font-family:var(--font-display);font-weight:800;font-size:1.8rem;color:#050708;flex-shrink:0;">\n          ${(t?.username||"U").charAt(0).toUpperCase()}\n        </div>\n        <div style="flex:1;">\n          <h2 style="font-family:var(--font-display);font-size:1.4rem;font-weight:800;text-transform:uppercase;margin-bottom:4px;">${escapeHtml(t?.username||"—")}</h2>\n          <div style="color:var(--text-secondary);font-size:.85rem;">${escapeHtml(t?.email||"")}</div>\n          ${"admin"===t?.role?'<span class="badge badge-teal" style="margin-top:6px;">Администратор</span>':'<span class="badge badge-silver" style="margin-top:6px;">Пользователь</span>'}\n        </div>\n        <div style="display:flex;gap:8px;flex-wrap:wrap;">\n          ${"admin"===t?.role?'<a href="/admin.html" class="btn btn-secondary btn-sm">⚙ Панель администратора</a>':""}\n          <button class="btn btn-danger btn-sm" onclick="handleLogout()">Выйти</button>\n        </div>\n      </div>\n    `}catch(t){e.innerHTML=`<div class="text-error">Ошибка загрузки профиля: ${escapeHtml(t.message)}</div>`}}async function loadFavorites(){const e=document.getElementById("fav-drivers-grid"),t=document.getElementById("fav-teams-grid");showLoading(e),showLoading(t);try{const n=await Favorites.list(),r=(n||[]).filter(e=>e.driver),a=(n||[]).filter(e=>e.constructor);renderFavDrivers(e,r),renderFavTeams(t,a)}catch(n){showError(e,n.message),showError(t,n.message)}}function renderFavDrivers(e,t){t.length?e.innerHTML=t.map(e=>{const t=e.driver,n=getDriverName(t,"—"),r=t.photo_url||"";return`\n      <div class="card" style="display:flex;align-items:center;gap:14px;">\n        ${r?`<img src="${escapeHtml(r)}" alt="${escapeHtml(n)}" style="width:52px;height:52px;border-radius:50%;object-fit:cover;border:2px solid var(--border);flex-shrink:0;" onerror="this.style.display='none'">`:`<div style="width:52px;height:52px;border-radius:50%;background:var(--bg-graphite);display:flex;align-items:center;justify-content:center;font-family:var(--font-display);font-weight:800;font-size:1.2rem;color:var(--teal);flex-shrink:0;">${n.charAt(0)}</div>`}\n        <div style="flex:1;min-width:0;">\n          <div style="font-weight:600;font-size:.9rem;margin-bottom:2px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${escapeHtml(n)}</div>\n          <div style="font-size:.75rem;color:var(--text-muted);">${escapeHtml(t.nationality||"")}</div>\n        </div>\n        <div style="display:flex;gap:6px;flex-shrink:0;">\n          <a href="/driver-detail.html?id=${t.id}" class="btn btn-ghost btn-sm btn-icon" title="Страница гонщика">→</a>\n          <button class="btn-favorite active" onclick="removeFavDriver(${e.driver_id}, this)" title="Убрать из избранного">★</button>\n        </div>\n      </div>\n    `}).join(""):showEmpty(e,"Нет избранных гонщиков","Добавьте гонщиков на странице «Гонщики»","⭐")}function renderFavTeams(e,t){t.length?e.innerHTML=t.map(e=>{const t=e.constructor,n=getConstructorName(t,"—"),r=t.logo_url||"";return`\n      <div class="card" style="display:flex;align-items:center;gap:14px;">\n        ${r?`<img src="${escapeHtml(r)}" alt="${escapeHtml(n)}" style="width:48px;height:48px;object-fit:contain;flex-shrink:0;" onerror="this.style.display='none'">`:`<div style="width:48px;height:48px;background:var(--bg-graphite);border-radius:var(--radius-md);display:flex;align-items:center;justify-content:center;font-family:var(--font-display);font-weight:800;color:var(--teal);flex-shrink:0;">${n.charAt(0)}</div>`}\n        <div style="flex:1;min-width:0;">\n          <div style="font-weight:600;font-size:.9rem;margin-bottom:2px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${escapeHtml(n)}</div>\n          <div style="font-size:.75rem;color:var(--text-muted);">${escapeHtml(t.nationality||"")}</div>\n        </div>\n        <div style="display:flex;gap:6px;flex-shrink:0;">\n          <a href="/constructor-detail.html?id=${t.id}" class="btn btn-ghost btn-sm btn-icon">→</a>\n          <button class="btn-favorite active" onclick="removeFavTeam(${e.constructor_id}, this)">★</button>\n        </div>\n      </div>\n    `}).join(""):showEmpty(e,"Нет избранных команд","Добавьте команды на странице «Команды»","⭐")}async function removeFavDriver(e,t){try{await Favorites.removeDriver(e),t.closest(".card")?.remove(),showToast("Удалено из избранного","info");const n=document.getElementById("fav-drivers-grid");n&&!n.querySelector(".card")&&showEmpty(n,"Нет избранных гонщиков","Добавьте гонщиков на странице «Гонщики»","⭐")}catch(e){showToast(e.message,"error")}}async function removeFavTeam(e,t){try{await Favorites.removeConstructor(e),t.closest(".card")?.remove(),showToast("Удалено из избранного","info");const n=document.getElementById("fav-teams-grid");n&&!n.querySelector(".card")&&showEmpty(n,"Нет избранных команд","Добавьте команды на странице «Команды»","⭐")}catch(e){showToast(e.message,"error")}}function initSettingsForm(){const e=document.getElementById("change-password-form");e&&e.addEventListener("submit",async t=>{t.preventDefault();const n=document.getElementById("current-password")?.value,r=document.getElementById("new-password")?.value,a=document.getElementById("confirm-new-password")?.value;if(!n||!r||!a)return void showToast("Заполните все поля","warning");if(r.length<6)return void showToast("Пароль должен быть не менее 6 символов","warning");if(r!==a)return void showToast("Пароли не совпадают","error");const i=e.querySelector('[type="submit"]');setButtonLoading(i,!0);try{await apiPut("/auth/password",{current_password:n,new_password:r}),showToast("Пароль изменён","success"),e.reset()}catch(e){showToast(e.message||"Ошибка","error")}finally{setButtonLoading(i,!1)}})}function setButtonLoading(e,t){e&&(e.disabled=t,e.dataset.originalText=e.dataset.originalText||e.textContent,e.textContent=t?"Загрузка...":e.dataset.originalText)}document.addEventListener("DOMContentLoaded",initProfilePage);